sys_atf_test_step.step:
(function step(assert, $library) {
    // Test Self-Service Actions CRUD operations
    // Create
    var gr = new GlideRecord('u_idp_self_service_action');
    gr.initialize();
    gr.u_name = 'Test Self-Service Action ATF';
    gr.u_type = 'test';
    gr.u_script = 'gs.log("test");';
    var id = gr.insert();
    assert.isTrue(id, 'Self-service action should be created');

    // Read
    gr = new GlideRecord('u_idp_self_service_action');
    gr.get(id);
    assert.equal(gr.u_name, 'Test Self-Service Action ATF', 'Action name should match');

    // Update
    gr.u_script = 'gs.log("test-updated");';
    gr.update();

    // Delete
    gr.deleteRecord();

    // Verify deletion
    gr = new GlideRecord('u_idp_self_service_action');
    gr.get(id);
    assert.isFalse(gr.isValid(), 'Self-service action should be deleted');
})(step, $library);
